css:
@media print {
  @page {
    size: A4 landscape;
    margin: 8px 10px;
  }
}

.attendance-wrapper {
  padding-right: 0;
}

.attendance-table {
  width: 100%;
  border-collapse: collapse;
  table-layout: fixed;
  font-size: 8px;
}

.attendance-table th,
.attendance-table td {
  border: 1px solid #000;
  padding-left: 0 !important;
  padding-right: 0 !important;
  padding-top: 1px;
  padding-bottom: 1px;
  text-align: center !important;
  vertical-align: middle !important;
  box-sizing: border-box;
  white-space: nowrap;
  overflow: hidden;
}

.attendance-title {
  font-size: 18px;
  font-weight: bold;
  padding: 8px 0;
  white-space: normal;
}

.attendance-meta {
  font-size: 11px;
  padding: 4px 0;
  text-align: center;
  white-space: normal;
}

.staff-on-duty {
  background-color: #e0e0e0;
  font-weight: bold;
  text-align: center;
}

.attendance-title,
.attendance-meta,
.staff-on-duty,
.attendance-legend {
  vertical-align: middle !important;
}

.signature-row td,
.signature-row th,
.stamp-row td,
.stamp-row th {
  vertical-align: middle !important;
  white-space: normal;
}

.no-attendance {
  background-color: #e0e0e0;
}

.attendance-legend {
  text-align: center;
  font-size: 10px;
  padding: 4px 0;
  white-space: normal;
}

.block-separator td {
  background-color: #333 !important;
  color: white !important;
  font-weight: bold !important;
  padding: 3px 6px !important;
  text-align: left !important;
  font-size: 10px !important;
  height: 20px !important;
  line-height: 1.2 !important;
  white-space: normal !important;
}

.col-day {
  font-size: 7.5px;
}

.text-left {
  text-align: left !important;
  white-space: normal;
  overflow: hidden;
  overflow-wrap: break-word;
  font-size: 8.5px;
}

html:
{# ======================================================
  BASIC DOC FIELDS
====================================================== #}
{% set project = doc.project %}
{% set site = doc.site %}
{% set month = doc.month %}
{% set year = doc.year | int %}
{% set is_shift_hours = (doc.attendance_based_on == "Shift Hours") %}
{# ======================================================
  FETCH ADDITIONAL DATA
====================================================== #}
{% set client_name = frappe.db.get_value("Project", project, "customer") if project else "" %}
{% set supervisor_name = frappe.db.get_value("User", doc.site_supervisor_user, "full_name") if doc.site_supervisor_user else "" %}
{# ======================================================
  BASIC AND OVERTIME DATA
====================================================== #}
{% set basic_data = doc.attendance_details or [] %}
{% set overtime_data = doc.overtime_details or [] %}
{# ======================================================
  STATUS MAP (for non-shift-hours mode)
====================================================== #}
{% set status_map = {
  "Present": "P",
  "Absent": "A",
  "On Leave": "OL",
  "Holiday": "H",
  "Day Off": "DO",
  "Client Day Off": "DO",
  "On Hold": "OH"
} %}
{# ======================================================
  DAYS IN MONTH (JINJA-ONLY CALCULATION)
====================================================== #}
{% set month_index = {
  "January": 1, "February": 2, "March": 3, "April": 4,
  "May": 5, "June": 6, "July": 7, "August": 8,
  "September": 9, "October": 10, "November": 11, "December": 12
}[month] %}
{% set month_days = {
  1: 31, 2: 28, 3: 31, 4: 30, 5: 31, 6: 30,
  7: 31, 8: 31, 9: 30, 10: 31, 11: 30, 12: 31
} %}
{% set days_in_month = month_days[month_index] %}
{# Leap year adjustment for February #}
{% if month_index == 2 and ((year % 4 == 0 and year % 100 != 0) or (year % 400 == 0)) %}
    {% set days_in_month = 29 %}
{% endif %}
{% set days = range(1, days_in_month + 1) %}
{# ======================================================
  TOTAL COLUMNS
====================================================== #}
{% set total_columns = 1 + 4 + 5 + 2 + days_in_month + 2 + 2 %}
{# ======================================================
  META ROW COLSPANS
====================================================== #}
{% set header_colspan = 3 %}
{% set remaining_cols = total_columns - (header_colspan * 3) %}
{% set project_data_colspan = remaining_cols * 40 // 100 %}
{% set site_data_colspan = remaining_cols * 40 // 100 %}
{% set month_data_colspan = remaining_cols - project_data_colspan - site_data_colspan %}

<div class="attendance-wrapper">
<table class="attendance-table">

<!-- ================= COLGROUP ================= -->
<colgroup>
  <!-- # -->
  <col style="width:22px">
  <!-- Employee ID (4 cols) -->
  <col style="width:25px"><col style="width:25px"><col style="width:25px"><col style="width:25px">
  <!-- Employee Name (5 cols) -->
  <col style="width:26px"><col style="width:26px"><col style="width:26px"><col style="width:26px"><col style="width:26px">
  <!-- Shift (2 cols) -->
  <col style="width:34px"><col style="width:34px">
  <!-- Day columns -->
  {% for d in days %}
  <col style="width:20px">
  {% endfor %}
  <!-- Working Days (2 cols) -->
  <col style="width:26px"><col style="width:26px">
  <!-- Days Off (2 cols) -->
  <col style="width:26px"><col style="width:26px">
</colgroup>

<!-- ================= TITLE ================= -->
<tr style="height: 60px;">
  <th colspan="{{ total_columns }}" class="attendance-title">
    Monthly Attendance Sheet (Combined)
  </th>
</tr>
<!-- ================= META ================= -->
<tr class="attendance-meta">
  <td colspan="{{ header_colspan }}"><strong>Project</strong></td>
  <td colspan="{{ project_data_colspan }}">{{ project }}</td>
  <td colspan="{{ header_colspan }}"><strong>Site</strong></td>
  <td colspan="{{ site_data_colspan }}">{{ site }}</td>
  <td colspan="{{ header_colspan }}"><strong>Month</strong></td>
  <td colspan="{{ month_data_colspan }}">{{ month }} {{ year }}</td>
</tr>
<!-- ================= HEADER (2 ROWS) ================= -->
<tr>
  <th class="col-sno" rowspan="2">#</th>
  <th class="col-empid" rowspan="2" colspan="4">Employee ID</th>
  <th class="col-name" rowspan="2" colspan="5">Employee Name</th>
  <th rowspan="2" colspan="2">Shift</th>
  {% for d in days %}
    <th class="col-day">{{ d }}</th>
  {% endfor %}
  <th class="col-total" rowspan="2" colspan="2">Working Days</th>
  <th class="col-total" rowspan="2" colspan="2">Days Off</th>
</tr>
<tr>
  {% for d in days %}
    {% set date_obj = frappe.utils.getdate([year, month_index, d]|join("-")) %}
    <th class="col-day">
      {{ frappe.utils.formatdate(date_obj, "EEE") }}
    </th>
  {% endfor %}
</tr>
{# ================= BLOCK A: BASIC ATTENDANCE ================= #}
{% if basic_data %}
<tr class="block-separator">
  <td colspan="{{ total_columns }}" style="background-color: #333; color: white; font-weight: bold; padding: 2px; text-align: left;">
   BASIC ATTENDANCE
  </td>
</tr>
{% for row in basic_data %}
<tr>
  <td>{{ loop.index }}</td>
  <td class="text-left" colspan="4">{{ row.employee_id or "" }}</td>
  <td class="text-left" colspan="5">{{ row.employee_name or "" }}</td>
  <td class="text-left" colspan="2">{{ row.shift or "" }}</td>

  {% set ns = namespace(present_days=0) %}

  {% for d in days %}
    {% if is_shift_hours %}
      {# Shift Hours mode: display hours and count working days #}
      {% set field = "day_" ~ d ~ "_hour" %}
      {% set value = row.get(field) %}
      {% set hours = frappe.utils.flt(value) %}
      {% if hours > 8 %}
        {% set ns.present_days = ns.present_days + 1 %}
      {% endif %}
      {% set display = frappe.utils.flt(value, 1) if value else "" %}
      <td class="{{ 'no-attendance' if not value else '' }}">{{ display }}</td>
    {% else %}
      {# Status mode: display status code and count Present days #}
      {% set field = "day_" ~ d %}
      {% set value = row.get(field) or "" %}
      {% if value == "Present" %}
        {% set ns.present_days = ns.present_days + 1 %}
      {% endif %}
      {% set display = status_map[value] if value in status_map else "" %}
      <td class="{{ 'no-attendance' if not value else '' }}">{{ display }}</td>
    {% endif %}
  {% endfor %}

  <td colspan="2">{{ ns.present_days }}</td>
  <td colspan="2">{{ row.off_days or 0 }}</td>
</tr>
{% endfor %}
{% endif %}
{# ================= SEPARATOR LINE ================= #}
{% if basic_data and overtime_data %}
<tr class="block-separator">
  <td colspan="{{ total_columns }}" style="background-color: #333; color: white; font-weight: bold; padding: 2px; text-align: left;">
    OVERTIME ATTENDANCE
  </td>
</tr>
{% endif %}
{# ================= BLOCK B: OVERTIME ATTENDANCE ================= #}
{% if overtime_data %}
{% for row in overtime_data %}
<tr>
  <td>{{ loop.index }}</td>
  <td class="text-left" colspan="4">{{ row.employee_id or "" }}</td>
  <td class="text-left" colspan="5">{{ row.employee_name or "" }}</td>
  <td class="text-left" colspan="2">{{ row.shift or "" }}</td>

  {% for d in days %}
    {% set status_field = "day_" ~ d %}
    {% set hour_field = "day_" ~ d ~ "_hour" %}
    {% set status = (row.get(status_field, "") | string).strip() %}
    {% set hours = (row.get(hour_field) | string).strip() %}

    {% if status in ["Client Day Off", "Day Off", "Holiday"] or hours in ["Client Day Off", "Day Off", "Holiday", "DO"] %}
      <td>DO</td>
    {% elif status in ["Absent", "On Leave"] %}
      <td>0</td>
    {% elif status == "Present" %}
      {% if hours and hours != "N/A" and hours not in ["Client Day Off", "Day Off", "Holiday", "DO"] %}
        {% set hour_value = frappe.utils.flt(hours, 1) %}
        <td>{{ hour_value if hour_value > 0 else "0" }}</td>
      {% else %}
        <td>0</td>
      {% endif %}
    {% else %}
      <td class="no-attendance"></td>
    {% endif %}
  {% endfor %}

  <td colspan="2"></td>
  <td colspan="2">{{ row.off_days or 0 }}</td>
</tr>
{% endfor %}
{% endif %}
<!-- ================= SIGNATURE / STAMP ROWS ================= -->
{% set col_1 = total_columns // 4 %}
{% set col_2 = total_columns // 4 %}
{% set col_3 = total_columns // 4 %}
{% set col_4 = total_columns - col_1 - col_2 - col_3 %}
<tr class="signature-row" style="height: 40px;">
  <td colspan="{{ col_1 }}"><strong>Supervisor Name &amp; Signature:</strong></td>
  <td colspan="{{ col_2 }}">{{ supervisor_name or "" }}</td>
  <td colspan="{{ col_3 }}"><strong>Client Name &amp; Signature:</strong></td>
  <td colspan="{{ col_4 }}">{{ client_name or "" }}</td>
</tr>
<tr class="stamp-row" style="height: 60px;">
  <td colspan="{{ col_1 }}">Stamp</td>
  <td colspan="{{ col_2 }}"></td>
  <td colspan="{{ col_3 }}">Stamp</td>
  <td colspan="{{ col_4 }}"></td>
</tr>
</table>
</div>
